          foregroundStyle: spec.key + 'ButtonForegroundStyle',
          action: spec.action,
          preeditStateAction: std.get(spec, 'preeditStateAction'),
        }),
        [spec.key + 'ButtonForegroundStyle']: makeForeground(theme, spec.foreground),
      },
    buttonNames(variant),
    {}
  );

