textFiles.jsonnet/lib/others.libsonnet:
local fromVh(s) =
  local num = std.substr(s, 0, std.length(s) - 2);
  std.parseJson(num);

local sumVh(arr) = (
  local sum = std.foldl(
    function(acc, v) acc + fromVh(v),
    arr,
    0
  );
  std.toString(sum) + 'vh'
);

local sumHeights(arr) = (
  if std.length(arr) == 0 then
    null  // з©әж•°з»„иҝ”еӣһ nullпјҲжҲ–иҮӘе®ҡд№үй»ҳи®ӨеҖјпјү
  else if std.type(arr[0]) == 'string' && std.endsWith(arr[0], 'vh') then
    sumVh(arr)
  else
    std.sum(arr)
);
// д»ҘдёҠдёәй”®зӣҳй«ҳеәҰжұӮе’ҢеҮҪж•°пјҢеӢҝеҠЁ

{
  // жқӮйЎ№и®ҫзҪ®
  // й”®зӣҳй«ҳеәҰпјҢе»әи®®з»ҹдёҖдҪҝз”ЁеҗҢдёҖеҚ•дҪҚпјҢдёҚиҰҒж··з”Ё
